import{_ as e,c as p,b as o,a as s,d as a,e as c,r as l,o as i}from"./app-B-w23q80.js";const u={},r={href:"https://github.com/coolclaws/deerflow-book",target:"_blank",rel:"noopener noreferrer"};function d(k,n){const t=l("ExternalLinkIcon");return i(),p("div",null,[n[2]||(n[2]=o(`<h1 id="第-11-章-长期记忆架构" tabindex="-1"><a class="header-anchor" href="#第-11-章-长期记忆架构"><span>第 11 章　长期记忆架构</span></a></h1><p>绝大多数 Agent 框架的会话在结束后即刻失忆——下一次对话从零开始，用户不得不反复自我介绍、重复偏好设定。DeerFlow 的做法截然不同：它在后台维护一套持久化的记忆系统，使 Agent 能够跨会话地&quot;认识&quot;用户、积累上下文、追踪目标。</p><p>本章将深入剖析这套记忆架构的数据模型、配置体系和缓存策略。</p><h2 id="_11-1-记忆的三层结构" tabindex="-1"><a class="header-anchor" href="#_11-1-记忆的三层结构"><span>11.1 记忆的三层结构</span></a></h2><p>打开 <code>updater.py</code> 中的 <code>_create_empty_memory()</code> 函数，可以看到记忆的骨架：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">_create_empty_memory</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> Any<span class="token punctuation">]</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token string">&quot;version&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;1.0&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string">&quot;lastUpdated&quot;</span><span class="token punctuation">:</span> datetime<span class="token punctuation">.</span>utcnow<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>isoformat<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token string">&quot;Z&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string">&quot;user&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token string">&quot;workContext&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span><span class="token string">&quot;summary&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;updatedAt&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string">&quot;personalContext&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span><span class="token string">&quot;summary&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;updatedAt&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string">&quot;topOfMind&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span><span class="token string">&quot;summary&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;updatedAt&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string">&quot;history&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token string">&quot;recentMonths&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span><span class="token string">&quot;summary&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;updatedAt&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string">&quot;earlierContext&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span><span class="token string">&quot;summary&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;updatedAt&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">            <span class="token string">&quot;longTermBackground&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span><span class="token string">&quot;summary&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;updatedAt&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string">&quot;facts&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这三层结构各有分工：</p><p><strong>第一层：用户画像（user）</strong> 捕捉用户&quot;是谁&quot;。</p><ul><li><code>workContext</code>：职业角色、公司、关键项目、主力技术栈（2-3 句话）。</li><li><code>personalContext</code>：语言能力、沟通偏好、兴趣领域（1-2 句话）。</li><li><code>topOfMind</code>：当前关注的多个并行焦点（3-5 句话），更新频率最高。</li></ul><p><strong>第二层：时间线（history）</strong> 记录用户&quot;做过什么&quot;。</p><ul><li><code>recentMonths</code>：近 1-3 个月的详细活动摘要（4-6 句话）。</li><li><code>earlierContext</code>：3-12 个月前的重要模式（3-5 句话）。</li><li><code>longTermBackground</code>：长期不变的基础背景（2-4 句话）。</li></ul><p><strong>第三层：事实库（facts）</strong> 存储离散、可检索的结构化知识点。</p><h2 id="_11-2-facts-的五种类别" tabindex="-1"><a class="header-anchor" href="#_11-2-facts-的五种类别"><span>11.2 Facts 的五种类别</span></a></h2><p>每条 fact 都携带 <code>category</code> 字段，取值来自五种类别：</p><table><thead><tr><th>类别</th><th>含义</th><th>示例</th></tr></thead><tbody><tr><td><code>preference</code></td><td>用户偏好</td><td>&quot;偏好使用 Vim 而非 VS Code&quot;</td></tr><tr><td><code>knowledge</code></td><td>专业知识</td><td>&quot;精通 Rust 和 WebAssembly&quot;</td></tr><tr><td><code>context</code></td><td>背景事实</td><td>&quot;在字节跳动担任高级工程师&quot;</td></tr><tr><td><code>behavior</code></td><td>行为模式</td><td>&quot;习惯先写测试再写实现&quot;</td></tr><tr><td><code>goal</code></td><td>目标意图</td><td>&quot;计划在 Q2 发布 v2.0&quot;</td></tr></tbody></table><p>在 <code>_apply_updates</code> 方法中，每条新 fact 被构造为完整的结构化条目：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line">fact_entry <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token string">&quot;id&quot;</span><span class="token punctuation">:</span> <span class="token string-interpolation"><span class="token string">f&quot;fact_</span><span class="token interpolation"><span class="token punctuation">{</span>uuid<span class="token punctuation">.</span>uuid4<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token builtin">hex</span><span class="token punctuation">[</span><span class="token punctuation">:</span><span class="token format-spec">8]</span><span class="token punctuation">}</span></span><span class="token string">&quot;</span></span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;content&quot;</span><span class="token punctuation">:</span> fact<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token string">&quot;content&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;category&quot;</span><span class="token punctuation">:</span> fact<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token string">&quot;category&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;context&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;confidence&quot;</span><span class="token punctuation">:</span> confidence<span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;createdAt&quot;</span><span class="token punctuation">:</span> now<span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;source&quot;</span><span class="token punctuation">:</span> thread_id <span class="token keyword">or</span> <span class="token string">&quot;unknown&quot;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">current_memory<span class="token punctuation">[</span><span class="token string">&quot;facts&quot;</span><span class="token punctuation">]</span><span class="token punctuation">.</span>append<span class="token punctuation">(</span>fact_entry<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_11-3-confidence-阈值-0-7-的门槛" tabindex="-1"><a class="header-anchor" href="#_11-3-confidence-阈值-0-7-的门槛"><span>11.3 Confidence 阈值：0.7 的门槛</span></a></h2><p>并非所有 LLM 抽取的 fact 都会被保留。<code>MemoryConfig</code> 中定义了置信度阈值：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">MemoryConfig</span><span class="token punctuation">(</span>BaseModel<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    fact_confidence_threshold<span class="token punctuation">:</span> <span class="token builtin">float</span> <span class="token operator">=</span> Field<span class="token punctuation">(</span></span>
<span class="line">        default<span class="token operator">=</span><span class="token number">0.7</span><span class="token punctuation">,</span></span>
<span class="line">        ge<span class="token operator">=</span><span class="token number">0.0</span><span class="token punctuation">,</span></span>
<span class="line">        le<span class="token operator">=</span><span class="token number">1.0</span><span class="token punctuation">,</span></span>
<span class="line">        description<span class="token operator">=</span><span class="token string">&quot;Minimum confidence threshold for storing facts&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 <code>_apply_updates</code> 中，只有达到阈值的 fact 才会入库：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line">confidence <span class="token operator">=</span> fact<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token string">&quot;confidence&quot;</span><span class="token punctuation">,</span> <span class="token number">0.5</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> confidence <span class="token operator">&gt;=</span> config<span class="token punctuation">.</span>fact_confidence_threshold<span class="token punctuation">:</span></span>
<span class="line">    <span class="token comment"># 入库</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Prompt 中对置信度给出了清晰的分级指引：</p><ul><li><strong>0.9-1.0</strong>：用户明确陈述的事实（&quot;我在做 X 项目&quot;）</li><li><strong>0.7-0.8</strong>：从行为中强烈推断的信息</li><li><strong>0.5-0.6</strong>：推测性模式（慎用，仅对清晰模式使用）</li></ul><p>默认阈值 0.7 意味着只有&quot;明确陈述&quot;和&quot;强烈推断&quot;的信息才会进入记忆。这个设计在信息保留和噪声过滤之间取得了平衡。</p><h2 id="_11-4-全局记忆-vs-per-agent-记忆" tabindex="-1"><a class="header-anchor" href="#_11-4-全局记忆-vs-per-agent-记忆"><span>11.4 全局记忆 vs Per-Agent 记忆</span></a></h2><p>DeerFlow 的记忆系统支持两种粒度。<code>_get_memory_file_path</code> 函数根据是否传入 <code>agent_name</code> 来决定存储路径：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">_get_memory_file_path</span><span class="token punctuation">(</span>agent_name<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> Path<span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">if</span> agent_name <span class="token keyword">is</span> <span class="token keyword">not</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> get_paths<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>agent_memory_file<span class="token punctuation">(</span>agent_name<span class="token punctuation">)</span></span>
<span class="line">    config <span class="token operator">=</span> get_memory_config<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> config<span class="token punctuation">.</span>storage_path<span class="token punctuation">:</span></span>
<span class="line">        p <span class="token operator">=</span> Path<span class="token punctuation">(</span>config<span class="token punctuation">.</span>storage_path<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span> p <span class="token keyword">if</span> p<span class="token punctuation">.</span>is_absolute<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">else</span> get_paths<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>base_dir <span class="token operator">/</span> p</span>
<span class="line">    <span class="token keyword">return</span> get_paths<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>memory_file</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><strong>全局记忆</strong>（<code>agent_name=None</code>）：所有 Agent 共享的用户画像，存储在 <code>memory.json</code>。</li><li><strong>Per-Agent 记忆</strong>（<code>agent_name=&quot;coder&quot;</code> 等）：特定 Agent 的专属记忆，存储在独立文件中。</li></ul><p>这种设计允许通用信息（如用户身份、语言偏好）全局共享，而领域特定知识（如编码风格偏好）由对应的 Agent 独立维护。</p><h2 id="_11-5-文件缓存机制-mtime-检测" tabindex="-1"><a class="header-anchor" href="#_11-5-文件缓存机制-mtime-检测"><span>11.5 文件缓存机制：mtime 检测</span></a></h2><p>频繁读写磁盘会拖慢响应速度。DeerFlow 采用了基于文件修改时间（mtime）的缓存策略：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line">_memory_cache<span class="token punctuation">:</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">,</span> <span class="token builtin">tuple</span><span class="token punctuation">[</span><span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> Any<span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token builtin">float</span> <span class="token operator">|</span> <span class="token boolean">None</span><span class="token punctuation">]</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">get_memory_data</span><span class="token punctuation">(</span>agent_name<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> Any<span class="token punctuation">]</span><span class="token punctuation">:</span></span>
<span class="line">    file_path <span class="token operator">=</span> _get_memory_file_path<span class="token punctuation">(</span>agent_name<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">try</span><span class="token punctuation">:</span></span>
<span class="line">        current_mtime <span class="token operator">=</span> file_path<span class="token punctuation">.</span>stat<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>st_mtime <span class="token keyword">if</span> file_path<span class="token punctuation">.</span>exists<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">else</span> <span class="token boolean">None</span></span>
<span class="line">    <span class="token keyword">except</span> OSError<span class="token punctuation">:</span></span>
<span class="line">        current_mtime <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line"></span>
<span class="line">    cached <span class="token operator">=</span> _memory_cache<span class="token punctuation">.</span>get<span class="token punctuation">(</span>agent_name<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> cached <span class="token keyword">is</span> <span class="token boolean">None</span> <span class="token keyword">or</span> cached<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">!=</span> current_mtime<span class="token punctuation">:</span></span>
<span class="line">        memory_data <span class="token operator">=</span> _load_memory_from_file<span class="token punctuation">(</span>agent_name<span class="token punctuation">)</span></span>
<span class="line">        _memory_cache<span class="token punctuation">[</span>agent_name<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">(</span>memory_data<span class="token punctuation">,</span> current_mtime<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span> memory_data</span>
<span class="line">    <span class="token keyword">return</span> cached<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>缓存字典 <code>_memory_cache</code> 以 <code>agent_name</code> 为键，值是 <code>(memory_data, file_mtime)</code> 的元组。每次读取时比较当前文件的 mtime 与缓存中的 mtime，仅在文件被修改后才重新加载。这种方式既保证了数据新鲜度，又避免了不必要的 I/O。</p><h2 id="_11-6-max-injection-tokens-限制" tabindex="-1"><a class="header-anchor" href="#_11-6-max-injection-tokens-限制"><span>11.6 max_injection_tokens 限制</span></a></h2><p>记忆注入系统提示词时不能无限膨胀。<code>MemoryConfig</code> 通过 <code>max_injection_tokens</code> 控制上限：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line">max_injection_tokens<span class="token punctuation">:</span> <span class="token builtin">int</span> <span class="token operator">=</span> Field<span class="token punctuation">(</span></span>
<span class="line">    default<span class="token operator">=</span><span class="token number">2000</span><span class="token punctuation">,</span></span>
<span class="line">    ge<span class="token operator">=</span><span class="token number">100</span><span class="token punctuation">,</span></span>
<span class="line">    le<span class="token operator">=</span><span class="token number">8000</span><span class="token punctuation">,</span></span>
<span class="line">    description<span class="token operator">=</span><span class="token string">&quot;Maximum tokens to use for memory injection&quot;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 <code>prompt.py</code> 的 <code>format_memory_for_injection</code> 中，使用 tiktoken 精确计算 token 数，超出限制时按比例截断：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line">token_count <span class="token operator">=</span> _count_tokens<span class="token punctuation">(</span>result<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> token_count <span class="token operator">&gt;</span> max_tokens<span class="token punctuation">:</span></span>
<span class="line">    char_per_token <span class="token operator">=</span> <span class="token builtin">len</span><span class="token punctuation">(</span>result<span class="token punctuation">)</span> <span class="token operator">/</span> token_count</span>
<span class="line">    target_chars <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span>max_tokens <span class="token operator">*</span> char_per_token <span class="token operator">*</span> <span class="token number">0.95</span><span class="token punctuation">)</span></span>
<span class="line">    result <span class="token operator">=</span> result<span class="token punctuation">[</span><span class="token punctuation">:</span>target_chars<span class="token punctuation">]</span> <span class="token operator">+</span> &quot;</span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>&quot;</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>默认 2000 tokens 大约可以容纳用户画像、近期历史和若干关键 facts，足以让 Agent &quot;认出&quot;用户而不会占据过多的上下文窗口。</p><h2 id="_11-7-完整配置一览" tabindex="-1"><a class="header-anchor" href="#_11-7-完整配置一览"><span>11.7 完整配置一览</span></a></h2><p><code>MemoryConfig</code> 的全部字段如下：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">MemoryConfig</span><span class="token punctuation">(</span>BaseModel<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    enabled<span class="token punctuation">:</span> <span class="token builtin">bool</span> <span class="token operator">=</span> <span class="token boolean">True</span>                    <span class="token comment"># 总开关</span></span>
<span class="line">    storage_path<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">=</span> <span class="token string">&quot;&quot;</span>                  <span class="token comment"># 自定义存储路径</span></span>
<span class="line">    debounce_seconds<span class="token punctuation">:</span> <span class="token builtin">int</span> <span class="token operator">=</span> <span class="token number">30</span>              <span class="token comment"># 防抖等待时间（1-300s）</span></span>
<span class="line">    model_name<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span>           <span class="token comment"># 记忆更新使用的模型</span></span>
<span class="line">    max_facts<span class="token punctuation">:</span> <span class="token builtin">int</span> <span class="token operator">=</span> <span class="token number">100</span>                    <span class="token comment"># 最大 facts 数量（10-500）</span></span>
<span class="line">    fact_confidence_threshold<span class="token punctuation">:</span> <span class="token builtin">float</span> <span class="token operator">=</span> <span class="token number">0.7</span>  <span class="token comment"># 置信度阈值</span></span>
<span class="line">    injection_enabled<span class="token punctuation">:</span> <span class="token builtin">bool</span> <span class="token operator">=</span> <span class="token boolean">True</span>          <span class="token comment"># 是否注入系统提示词</span></span>
<span class="line">    max_injection_tokens<span class="token punctuation">:</span> <span class="token builtin">int</span> <span class="token operator">=</span> <span class="token number">2000</span>        <span class="token comment"># 注入 token 上限（100-8000）</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当 <code>max_facts</code> 上限被触及时，系统会按置信度排序保留 top-N：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">if</span> <span class="token builtin">len</span><span class="token punctuation">(</span>current_memory<span class="token punctuation">[</span><span class="token string">&quot;facts&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token operator">&gt;</span> config<span class="token punctuation">.</span>max_facts<span class="token punctuation">:</span></span>
<span class="line">    current_memory<span class="token punctuation">[</span><span class="token string">&quot;facts&quot;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token builtin">sorted</span><span class="token punctuation">(</span></span>
<span class="line">        current_memory<span class="token punctuation">[</span><span class="token string">&quot;facts&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">        key<span class="token operator">=</span><span class="token keyword">lambda</span> f<span class="token punctuation">:</span> f<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token string">&quot;confidence&quot;</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        reverse<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">[</span><span class="token punctuation">:</span> config<span class="token punctuation">.</span>max_facts<span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>低置信度的 facts 会被自然淘汰，确保记忆库始终保留最有价值的信息。</p><h2 id="_11-8-memory-json-完整结构示例" tabindex="-1"><a class="header-anchor" href="#_11-8-memory-json-完整结构示例"><span>11.8 memory.json 完整结构示例</span></a></h2><p>前面几节分别介绍了三层数据模型的骨架，但空结构不足以建立直觉。下面给出一个经过多轮对话积累后的真实 <code>memory.json</code> 示例，读者可以对照各字段的实际填充效果：</p><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json" data-title="json"><pre><code><span class="line"><span class="token punctuation">{</span></span>
<span class="line">  <span class="token property">&quot;version&quot;</span><span class="token operator">:</span> <span class="token string">&quot;1.0&quot;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;lastUpdated&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2025-06-15T10:23:45Z&quot;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;user&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token property">&quot;workContext&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;summary&quot;</span><span class="token operator">:</span> <span class="token string">&quot;字节跳动高级工程师，主导 DeerFlow 框架开发，技术栈以 Python + LangChain + FastAPI 为核心，同时熟悉 TypeScript 前端开发。&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;updatedAt&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2025-06-15T10:23:45Z&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;personalContext&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;summary&quot;</span><span class="token operator">:</span> <span class="token string">&quot;中英文双语，偏好简洁直接的技术沟通风格，对 Vim 和终端工具链有强烈偏好。&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;updatedAt&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2025-06-14T08:12:30Z&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;topOfMind&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;summary&quot;</span><span class="token operator">:</span> <span class="token string">&quot;正在准备 DeerFlow 2.0 的开源发布，重点关注文档完善和 MCP 扩展生态。同时在优化 Sub-Agent 的并发调度策略，目标是将任务完成时间缩短 40%。近期还在评估 Claude 和 GPT-4o 作为默认模型的性价比。&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;updatedAt&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2025-06-15T10:23:45Z&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;history&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token property">&quot;recentMonths&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;summary&quot;</span><span class="token operator">:</span> <span class="token string">&quot;过去两个月主要在重构 Agent 中间件管道，将原有的硬编码流程迁移到可插拔的 Middleware 架构。完成了 MemoryMiddleware、ToolFilterMiddleware 和 CheckpointerMiddleware 的实现与测试。同时在 CI 中引入了端到端的 Agent 行为回归测试，覆盖率从 62% 提升到 85%。&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;updatedAt&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2025-06-15T10:23:45Z&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;earlierContext&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;summary&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2025 年初完成了 DeerFlow 1.0 到 2.0 的架构迁移，核心变化包括从单体 Agent 拆分为 Lead/Sub-Agent 双层架构，以及引入 LangGraph 作为流程编排引擎。期间还主导了内部 Hackathon，产出了三个基于 DeerFlow 的概念验证项目。&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;updatedAt&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2025-06-01T15:30:00Z&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token property">&quot;longTermBackground&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;summary&quot;</span><span class="token operator">:</span> <span class="token string">&quot;5 年 Python 后端开发经验，从 Django 转型到 AI Agent 领域。在加入字节跳动之前曾在一家 NLP 初创公司负责对话系统的后端服务开发，对大规模并发和分布式架构有实践经验。&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;updatedAt&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2025-05-20T09:00:00Z&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;facts&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;id&quot;</span><span class="token operator">:</span> <span class="token string">&quot;fact_a1b2c3d4&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;content&quot;</span><span class="token operator">:</span> <span class="token string">&quot;偏好使用 Vim 进行代码编辑，已使用超过 3 年&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;category&quot;</span><span class="token operator">:</span> <span class="token string">&quot;preference&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;confidence&quot;</span><span class="token operator">:</span> <span class="token number">0.95</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;createdAt&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2025-06-10T14:20:00Z&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;source&quot;</span><span class="token operator">:</span> <span class="token string">&quot;thread_abc123&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;id&quot;</span><span class="token operator">:</span> <span class="token string">&quot;fact_e5f6g7h8&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;content&quot;</span><span class="token operator">:</span> <span class="token string">&quot;项目中使用 PostgreSQL 作为 Checkpointer 后端&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;category&quot;</span><span class="token operator">:</span> <span class="token string">&quot;knowledge&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;confidence&quot;</span><span class="token operator">:</span> <span class="token number">0.85</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;createdAt&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2025-06-12T11:30:00Z&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;source&quot;</span><span class="token operator">:</span> <span class="token string">&quot;thread_def456&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">]</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>注意几个细节：<code>topOfMind</code> 的 <code>updatedAt</code> 与顶层 <code>lastUpdated</code> 一致，说明这是最近一次更新中被修改的字段；而 <code>personalContext</code> 的时间戳较早，意味着该字段已经稳定了一段时间。<code>facts</code> 数组中的 <code>source</code> 字段指向产生该 fact 的对话线程 ID，方便后续溯源和去重。</p><h2 id="_11-9-confidence-评分的工作机制" tabindex="-1"><a class="header-anchor" href="#_11-9-confidence-评分的工作机制"><span>11.9 Confidence 评分的工作机制</span></a></h2><p>11.3 节简要提到了置信度阈值，这里深入解析 LLM 如何为每条 fact 打分。关键在于 <code>prompt.py</code> 中的 <code>MEMORY_UPDATE_PROMPT</code>——它向 LLM 提供了明确的评分指南，而非让模型自由发挥。</p><p><strong>0.9-1.0 分段：用户明确陈述。</strong> 当用户在对话中直接说出&quot;我在做 X 项目&quot;、&quot;我的角色是 Y&quot;这类第一人称断言时，LLM 应给予最高置信度。这类信息几乎没有歧义，直接来自用户本人的声明。</p><p><strong>0.7-0.8 分段：强烈暗示。</strong> 用户虽未直接陈述，但通过反复讨论某项技术、多次执行同一类操作等行为模式，可以高度推断的信息。例如用户连续五次让 Agent 用 Python 写代码而从未选择其他语言，可以推断其偏好 Python。</p><p><strong>0.5-0.6 分段：稀疏推测。</strong> 仅从少量证据中推断出的信息，应当慎用。Prompt 明确指示 LLM 只在识别到清晰模式时才使用这个分段。</p><p>0.7 阈值的实际效果是：只有&quot;明确陈述&quot;和&quot;强烈暗示&quot;两个分段的 fact 能够存活。在 <code>_apply_updates</code> 方法中，低于阈值的 fact 被静默丢弃，不会产生任何日志或通知。当 <code>max_facts</code> 上限触发时，系统按 confidence 降序排列，仅保留 top-N 条目——这意味着 0.7 分的 fact 会比 0.95 分的 fact 更早被淘汰，形成了一个自然的优先级梯度。</p><h2 id="_11-10-max-injection-tokens-的计算方式" tabindex="-1"><a class="header-anchor" href="#_11-10-max-injection-tokens-的计算方式"><span>11.10 max_injection_tokens 的计算方式</span></a></h2><p>11.6 节展示了截断的代码片段，这里补充完整的 token 计算流程。<code>format_memory_for_injection()</code> 内部调用 <code>_count_tokens()</code> 函数，该函数首先尝试加载 tiktoken 库并使用 <code>cl100k_base</code> 编码器——这是 GPT-4 和 GPT-3.5 系列共用的 tokenizer。如果运行环境中未安装 tiktoken，则回退到 <code>len(text) / 4</code> 的粗略估算。</p><p>格式化过程按照严格的优先级顺序拼接各部分内容。首先是用户画像区块，依次写入 <code>workContext</code>、<code>personalContext</code> 和 <code>topOfMind</code> 的摘要；然后是历史区块，依次写入 <code>recentMonths</code>、<code>earlierContext</code> 和 <code>longTermBackground</code>。这个顺序反映了信息的即时重要性——&quot;用户是谁&quot;比&quot;用户过去做了什么&quot;更关键。</p><p>当拼接结果的 token 数超过 <code>max_injection_tokens</code>（默认 2000）时，系统根据 <code>char_per_token = len(result) / token_count</code> 计算字符与 token 的比率，然后乘以目标 token 数再乘以 0.95 的安全系数，得到截断点字符数。最终结果被包裹在 <code>&lt;memory&gt;...&lt;/memory&gt;</code> XML 标签中注入系统提示词。0.95 的安全系数确保截断后的实际 token 数不会因为字符到 token 映射的非线性而意外超限。</p><h2 id="_11-11-per-agent-记忆-vs-全局记忆" tabindex="-1"><a class="header-anchor" href="#_11-11-per-agent-记忆-vs-全局记忆"><span>11.11 per-agent 记忆 vs 全局记忆</span></a></h2><p>11.4 节介绍了两种记忆粒度的存储路径，这里进一步分析其使用场景和数据流。</p><p><strong>全局记忆</strong>（<code>agent_name=None</code>）存储在 <code>{base_dir}/memory.json</code>，包含跨 Agent 通用的用户信息：身份、语言偏好、沟通风格等。无论用户与哪个 Agent 交互，这些信息都应该被感知到。</p><p><strong>Per-Agent 记忆</strong>（如 <code>agent_name=&quot;assistant&quot;</code>）存储在 <code>{base_dir}/agents/assistant/memory.json</code>，包含该 Agent 特有的上下文。典型场景是：编码 Agent 记住用户的代码风格偏好（缩进方式、命名约定、测试框架选择），而写作 Agent 记住用户的文风偏好（正式程度、段落长度、术语使用）。两者互不干扰。</p><p><code>MemoryMiddleware</code> 在初始化时接收 <code>agent_name</code> 参数，该值来自 Lead Agent 的配置。当中间件触发记忆更新时，会将 <code>agent_name</code> 传递给 <code>update_memory()</code> 和 <code>get_memory_data()</code>，从而定位到正确的 memory 文件。两种记忆使用完全相同的数据结构和更新机制（<code>_apply_updates</code>），区别仅在于文件路径。这种设计使得记忆系统的核心逻辑无需为不同粒度编写不同代码，降低了维护成本。</p><h2 id="_11-12-记忆注入的时机与格式" tabindex="-1"><a class="header-anchor" href="#_11-12-记忆注入的时机与格式"><span>11.12 记忆注入的时机与格式</span></a></h2><p>记忆数据最终要进入 LLM 的上下文窗口才能发挥作用。注入发生在 <code>lead_agent/prompt.py</code> 的 <code>apply_prompt_template()</code> 函数中：该函数在构建完整的系统提示词时，调用 <code>_get_memory_context(agent_name)</code> 加载并格式化记忆数据，然后通过 <code>SYSTEM_PROMPT_TEMPLATE</code> 中的 <code>{memory_context}</code> 占位符将其插入。</p><p>注入后的记忆区块具有如下格式：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text" data-title="text"><pre><code><span class="line">&lt;memory&gt;</span>
<span class="line">User Context:</span>
<span class="line">- Work: [workContext summary]</span>
<span class="line">- Personal: [personalContext summary]</span>
<span class="line">- Current Focus: [topOfMind summary]</span>
<span class="line"></span>
<span class="line">History:</span>
<span class="line">- Recent: [recentMonths summary]</span>
<span class="line">- Earlier: [earlierContext summary]</span>
<span class="line">&lt;/memory&gt;</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用 XML 标签包裹有两个好处：一是让 LLM 能够清晰地区分记忆内容与其他系统指令；二是方便后续做 token 统计和调试日志的提取。</p><p>注入受两个条件门控：<code>injection_enabled</code> 必须为 <code>True</code>，且实际存在非空的记忆数据。若记忆文件为空或不存在，<code>{memory_context}</code> 占位符会被替换为空字符串，不会在系统提示词中留下任何痕迹。</p><p>值得注意的是，Sub-Agent 的流水线中不包含 <code>MemoryMiddleware</code>，因此它们不会接收记忆注入。这是有意为之——Sub-Agent 执行的是具体的工具调用任务（搜索、代码执行等），它们需要的上下文由 Lead Agent 在任务分发时显式传递，而非从长期记忆中隐式获取。这种分离避免了记忆信息在多层 Agent 间重复注入导致的 token 浪费。</p><h2 id="小结" tabindex="-1"><a class="header-anchor" href="#小结"><span>小结</span></a></h2><p>DeerFlow 的长期记忆架构通过三层数据模型（用户画像、时间线、事实库）完整地刻画了用户的身份、历史和碎片化知识。五种 fact 类别覆盖了从偏好到目标的全部维度，0.7 的置信度阈值在信息保留与噪声过滤之间取得了平衡。mtime 缓存避免了不必要的磁盘 I/O，<code>max_injection_tokens</code> 防止记忆注入占用过多上下文窗口。全局记忆与 per-agent 记忆的双轨设计，则在信息共享与领域隔离之间找到了恰当的折中。下一章我们将深入记忆更新的流水线——从对话结束到 <code>memory.json</code> 发生变化，中间究竟经历了哪些步骤。</p><hr>`,75)),s("p",null,[n[1]||(n[1]=a("来源: ",-1)),s("a",r,[n[0]||(n[0]=a("DeerFlow Book",-1)),c(t)])])])}const v=e(u,[["render",d]]),g=JSON.parse('{"path":"/docs/Agent/DeerFlow/11-memory-architecture.html","title":"第 11 章　长期记忆架构","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"11.1 记忆的三层结构","slug":"_11-1-记忆的三层结构","link":"#_11-1-记忆的三层结构","children":[]},{"level":2,"title":"11.2 Facts 的五种类别","slug":"_11-2-facts-的五种类别","link":"#_11-2-facts-的五种类别","children":[]},{"level":2,"title":"11.3 Confidence 阈值：0.7 的门槛","slug":"_11-3-confidence-阈值-0-7-的门槛","link":"#_11-3-confidence-阈值-0-7-的门槛","children":[]},{"level":2,"title":"11.4 全局记忆 vs Per-Agent 记忆","slug":"_11-4-全局记忆-vs-per-agent-记忆","link":"#_11-4-全局记忆-vs-per-agent-记忆","children":[]},{"level":2,"title":"11.5 文件缓存机制：mtime 检测","slug":"_11-5-文件缓存机制-mtime-检测","link":"#_11-5-文件缓存机制-mtime-检测","children":[]},{"level":2,"title":"11.6 max_injection_tokens 限制","slug":"_11-6-max-injection-tokens-限制","link":"#_11-6-max-injection-tokens-限制","children":[]},{"level":2,"title":"11.7 完整配置一览","slug":"_11-7-完整配置一览","link":"#_11-7-完整配置一览","children":[]},{"level":2,"title":"11.8 memory.json 完整结构示例","slug":"_11-8-memory-json-完整结构示例","link":"#_11-8-memory-json-完整结构示例","children":[]},{"level":2,"title":"11.9 Confidence 评分的工作机制","slug":"_11-9-confidence-评分的工作机制","link":"#_11-9-confidence-评分的工作机制","children":[]},{"level":2,"title":"11.10 max_injection_tokens 的计算方式","slug":"_11-10-max-injection-tokens-的计算方式","link":"#_11-10-max-injection-tokens-的计算方式","children":[]},{"level":2,"title":"11.11 per-agent 记忆 vs 全局记忆","slug":"_11-11-per-agent-记忆-vs-全局记忆","link":"#_11-11-per-agent-记忆-vs-全局记忆","children":[]},{"level":2,"title":"11.12 记忆注入的时机与格式","slug":"_11-12-记忆注入的时机与格式","link":"#_11-12-记忆注入的时机与格式","children":[]},{"level":2,"title":"小结","slug":"小结","link":"#小结","children":[]}],"git":{"createdTime":1775034173000,"updatedTime":1775034173000,"contributors":[{"name":"Gresdy","email":"1248824030@qq.com","commits":1}]},"filePathRelative":"docs/Agent/DeerFlow/11-memory-architecture.md"}');export{v as comp,g as data};
